// Proxy-like catch-all for forwarding to downstream microservices
app.all('/api/services/:service/*', authenticateToken(), (req, res) => {
  // In a real gateway, you would proxy the request to the downstream service
  // and attach verified identity info as headers
  const downstreamHeaders = {
    'X-Authenticated-Sub': req.auth.sub,
    'X-Authenticated-Client': req.auth.clientId,
    'X-Authenticated-Scopes': req.auth.scopes.join(' '),
    'X-Request-ID': req.requestId,
  };

  res.json({
    message: `Would proxy to service: ${req.params.service}`,
    path: req.params[0],
    method: req.method,
    downstreamHeaders,
    authenticatedUser: req.auth.sub,
  });
});

// 404 handler
